def build_url(self, start: int = 0) -> str:
    params = {
        "search_query": self.query,
        "sortBy": self.sort_by,
        "sortOrder": "descending",
        "start": start,
        "max_results": self.max_results,
    }
    return self.BASE_URL + "?" + urllib.parse.urlencode(params)
